code = """# Calculate average ratings for each children's book with reviews from 2020 onwards
import json

# Get review data
reviews_key = 'var_functions.query_db:36'
reviews = locals()[reviews_key]
if isinstance(reviews, str):
    with open(reviews, 'r') as f:
        reviews = json.load(f)

# Get children's books data
books_key = 'var_functions.query_db:22'
books = locals()[books_key]
if isinstance(books, str):
    with open(books, 'r') as f:
        books = json.load(f)

# Map book_id to book details
book_map = {book['book_id']: book for book in books}

# Group reviews by book
from collections import defaultdict
book_reviews = defaultdict(list)
for review in reviews:
    purchase_id = review['purchase_id']
    book_id = purchase_id.replace('purchaseid_', 'bookid_')
    if book_id in book_map:
        rating = float(review['rating'])
        book_reviews[book_id].append(rating)

# Calculate average rating for each book
results = []
for book_id, ratings in book_reviews.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        book = book_map[book_id]
        results.append({
            'title': book['title'],
            'book_id': book_id,
            'average_rating': round(avg_rating, 2),
            'review_count': len(ratings),
            'categories': book['categories']
        })

# Sort by average rating descending
results.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'books_meeting_criteria': results,
    'total_count': len(results)
}))"""

